mapper.select:
SELECT COUNT(*) FROM provider_channel_model
WHERE provider_channel_id = #{channelId} AND upstream_model_id = #{upstreamModelId}
  AND deleted_at IS NULL
AND id <> #{excludeId}

mapper.update:
UPDATE provider_channel_model
SET last_synced_at = NOW(), last_sync_summary = NULL, updated_at = NOW()
WHERE provider_channel_id = #{channelId}
  AND upstream_model_id = #{upstreamModelId}
  AND deleted_at IS NULL

UPDATE provider_channel_model SET last_sync_summary = #{summary}, updated_by = #{updatedBy}, updated_at = NOW() WHERE provider_channel_id = #{channelId} AND deleted_at IS NULL
AND 1 = 1
AND upstream_model_id NOT IN #{u}
